#!/usr/bin/env bash

# This script packages and uploads sysroots generated by create_sysroot.py.

set -e

arch="arm64"
copy_only=0

while getopts "ha:c" opt; do
    case $opt in
        h)
            echo "Usage: $0 [-h] [-a <arm64|armhf>] [-c]"
            echo "    -h    Displays this help message"
            echo "    -a    Architecture (arm64 or armhf, default: arm64)"
            echo "    -c    Copy only, do not upload to CIPD"
            exit 0
            ;;
        a)
            arch=$OPTARG
            if [ "$arch" != "arm64" ] && [ "$arch" != "armhf" ]; then
                echo "Invalid architecture: $arch. Must be arm64 or armhf."
                exit 1
            fi
            ;;
        c)
            copy_only=1
            ;;
    esac
done

if [ "$arch" = "arm64" ]; then
    OUTPUT_DIR=ubuntu-24.04-aarch64-sysroot
    PACKAGE=experimental/matter/sysroot/ubuntu-24.04-aarch64
    PACKAGE_DESC="AArch64 sysroot for cross-compiling matter SDK examples"
elif [ "$arch" = "armhf" ]; then
    OUTPUT_DIR=ubuntu-24.04-armhf-sysroot
    PACKAGE=experimental/matter/sysroot/ubuntu-24.04-armhf
    PACKAGE_DESC="ARMhf sysroot for cross-compiling matter SDK examples"
fi

if ! [ -d "$OUTPUT_DIR" ]; then
    echo "Error: Directory $OUTPUT_DIR does not exist."
    echo "Please run create_sysroot.py first to create it."
    exit 1
fi

echo "Using existing sysroot directory: $OUTPUT_DIR"

if [ "$copy_only" -eq 0 ]; then
    echo "Creating cipd definition"
    cat >cipd.yaml <<TEXTEND
package: $PACKAGE
description: $PACKAGE_DESC
install_mode: copy
data:
  - dir: "$OUTPUT_DIR"
TEXTEND

    TODAY=$(date '+%Y.%m.%d')
    PACKAGE_VERSION="build-$TODAY"

    # NOTE: sufficient permissions are required to be able to upload this.
    #       Login is a prerequisite:
    #
    #    cipd auth-login
    #
    echo "Uploading package tagged '$PACKAGE_VERSION' to $PACKAGE ..."
    cipd create -pkg-def=cipd.yaml -tag "version:$PACKAGE_VERSION"

    echo "Updating version to latest"
    cipd set-ref "$PACKAGE" -version "version:$PACKAGE_VERSION" -ref latest
else
    echo "Copy-only mode enabled. Skipping CIPD package creation and upload."
fi
